export const getGetRewardsUrl = () => {
  return `/api/rewards`;
};

export const getRewards = async (
  options?: RequestInit,
): Promise<CoinTransaction[]> => {
  return customFetch<CoinTransaction[]>(getGetRewardsUrl(), {
    ...options,
    method: "GET",
  });
};

export const getGetRewardsQueryKey = () => {
  return [`/api/rewards`] as const;
};

export const getGetRewardsQueryOptions = <
  TData = Awaited<ReturnType<typeof getRewards>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getRewards>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetRewardsQueryKey();

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getRewards>>> = ({
    signal,
  }) => getRewards({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getRewards>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

